import{_ as e,o as l,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const t="/assets/Image.8JxaHzay.png",i="/assets/Image-(2).BGE_gK3o.png",m="/assets/Image-(3).D1gYfLac.png",d="/assets/Image-(4).DK1fTtX1.png",b=JSON.parse('{"title":"5_cuda_matmul","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/study/멀티코어및GPU프로그래밍/5_cuda_matmul.md","filePath":"outta-space/study/멀티코어및GPU프로그래밍/5_cuda_matmul.md"}'),c={name:"outta-space/study/멀티코어및GPU프로그래밍/5_cuda_matmul.md"};function s(h,a,n,u,_,p){return l(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="_5-cuda-matmul" tabindex="-1">5_cuda_matmul <a class="header-anchor" href="#_5-cuda-matmul" aria-label="Permalink to &quot;5_cuda_matmul&quot;">​</a></h1><p>흐름을 다시 살펴봅시다.</p><h2 id="cuda-memory-model" tabindex="-1">CUDA Memory model <a class="header-anchor" href="#cuda-memory-model" aria-label="Permalink to &quot;CUDA Memory model&quot;">​</a></h2><p><img src="'+t+'" alt="Image.png"></p><p>Grid - Block - Thread 구조로 이루어져 있다. 여기서 thread는 자신의 reg에서 데이터를 가져오며, block은 내부에 shared memory를 가진다. 가장 외부의 grid는 global memory, constant memory를 가진다.</p><p>reg는 thread 사이에 공유되지 않으며, 공유는 shared memory를 이용해야 한다.</p><p><img src="'+i+'" alt="Image.png"></p><p>이는 사용자가 직접 데이터를 원하는 공간에 할당하기 위한 qualifiers이다. 일반 local variable은 register에 저장되고, <code>__shared__</code> 는 shared memory에 저장시킨다. device를 그냥 사용하면 global에, constant를 사용하면 constant memory에 저장시킨다.</p><h2 id="thread-scheduling" tabindex="-1">Thread Scheduling <a class="header-anchor" href="#thread-scheduling" aria-label="Permalink to &quot;Thread Scheduling&quot;">​</a></h2><p><img src="'+m+'" alt="Image.png"></p><p>일반적인 matmul을 생각해봤을 때, 연속적인 P(i, j) 접근은 global memory에 너무 자주 접근을 유발해 bottleneck이 생길 수 있다. bandwidth를 낭비하는 것은 물론이다. 이것은 왜 cache가 커버해주지 못할까?</p><ol><li>일단 GPU의 cache는 생각보다 thread당 충분하지 않다. (물론 나중에는 아니라고 나오지만)</li><li>애초에 데이터가 저장되는 방식이 cache friendly하지 않음. (cache는 temporal locality를 책임지지만 spatial locality는 책임지지 않기 때문)</li></ol><p><img src="'+d+'" alt="Image.png"></p><p>그래서 매번 메모리 접근을 하는 것을 막기 위해서 sum이라는 local variable에 결과값을 저장하기로 한다.</p><h2 id="threadblocks" tabindex="-1">Threadblocks <a class="header-anchor" href="#threadblocks" aria-label="Permalink to &quot;Threadblocks&quot;">​</a></h2><ul><li>계산해야 하는 output 행렬의 구역을 나눠서 threadblock에 할당하는 방법이다.</li><li>이는 dimGrid, dimBlock으로 커널에 전달된다.</li></ul><h3 id="shared-memory" tabindex="-1">Shared memory <a class="header-anchor" href="#shared-memory" aria-label="Permalink to &quot;Shared memory&quot;">​</a></h3><ul><li>위의 방법을 쓰면 메모리 접근 횟수는 줄일 수 있지만 결국 cache를 사용하지 못한다는 근본적인 문제를 해결하지 못한다.</li><li>그럴 때 사용하는 것이 <strong>shared memory</strong>이다. 이는 threadblock 내부에서 공유하는 메모리로, 블록 내의 스레드끼리 데이터를 공유할 수 있다.</li><li><code>__shared__</code>로 선언할 수 있다.</li><li>마지막 결과는 shared memory에서 global memory로 옮겨진다.</li><li><code>__syncthread__</code>로 각 단계 (shared memory 저장, element 계산) 를 sync 해주어야 한다. 이것이 barrier의 역할을 한다. (다만 threadblock 내부에서만 유효함)</li></ul><h3 id="how-large-of-a-tile" tabindex="-1">How large of a tile? <a class="header-anchor" href="#how-large-of-a-tile" aria-label="Permalink to &quot;How large of a tile?&quot;">​</a></h3><ul><li>tile의 사이즈가 커질수록 좋은 건 맞지만, 계산에 따라 사용하는 shared memory의 크기는 동일하다.</li><li>남은 shared memory는 어떻게 쓸까? <ul><li>한 thread가 더 많은 element를 계산하도록 하면 됨. (지금까지는 한 개의 element만 계산했음)</li></ul></li></ul><h3 id="coalescing" tabindex="-1">Coalescing <a class="header-anchor" href="#coalescing" aria-label="Permalink to &quot;Coalescing&quot;">​</a></h3><ul><li>위에서 볼 수 있듯이, M을 접근하는 게 row-wise이기 때문에 더 빨라보이지만, 사실은 column-wise인 N이 더 빠르다.</li><li>N은 column-wise로 접근해 다른 thread끼리 연속된 데이터에 접근할 수 있지만, M은 row-wise로 접근해 thread가 떨어진 데이터에 접근하기 때문이다. - 메모리 접근이 애초에 느림.</li><li>그래서 연속으로 접근할 수 있도록 데이터 배열을 임의로 바꾸는게 corner turning이다. 이것이 된 상태를 coalesced 됐다고 한다.</li></ul>',22)])])}const y=e(c,[["render",s]]);export{b as __pageData,y as default};
